namespace sv_219298d83a2d4e85ac6f11724fbe0645.Services;

public class AppointmentService
{
    private static readonly List<string> _doctors = new()
    {
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    };

    private static readonly List<string> _timeSlots = new()
    {
        "9:00 AM",
        "9:30 AM",
        "10:00 AM",
        "10:30 AM",
        "11:00 AM",
        "11:30 AM",
        "1:00 PM",
        "1:30 PM",
        "2:00 PM",
        "2:30 PM",
        "3:00 PM",
        "3:30 PM"
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(_doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return all time slots regardless of doctor/date
        return Task.FromResult(new List<string>(_timeSlots));
    }

    /// <summary>
    /// Validates patient/appointment data against server-side business rules.
    /// Returns a dictionary of field name -> error message for any validation failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        // Reject self-pay with doctors who don't accept it
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Simulate race condition on time slot
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_219298d83a2d4e85ac6f11724fbe0645.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label" for="patientName">Patient Name</label>
        <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
        <ValidationMessage For="() => Model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="email">Email</label>
        <InputText id="email" class="form-control" @bind-Value="Model.Email" />
        <ValidationMessage For="() => Model.Email" />
        @if (!string.IsNullOrEmpty(serverErrors.GetValueOrDefault("Email")))
        {
            <div class="validation-message">@serverErrors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="phone">Phone</label>
        <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
        <ValidationMessage For="() => Model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="insurance">Insurance Provider</label>
        <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => Model.InsuranceProvider" />
    </div>

    @if (showStep2)
    {
        <h3>Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label" for="doctor">Preferred Doctor</label>
            <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor" @bind-Value:after="OnDoctorOrDateChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Doctor" />
            @if (!string.IsNullOrEmpty(serverErrors.GetValueOrDefault("Doctor")))
            {
                <div class="validation-message">@serverErrors["Doctor"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="date">Date</label>
            <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" @bind-Value:after="OnDoctorOrDateChanged" />
            <ValidationMessage For="() => Model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="timeSlot">Time Slot</label>
            <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.TimeSlot" />
            @if (!string.IsNullOrEmpty(serverErrors.GetValueOrDefault("TimeSlot")))
            {
                <div class="validation-message">@serverErrors["TimeSlot"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="reason">Reason for Visit</label>
            <InputTextArea id="reason" class="form-control" @bind-Value="Model.Reason" rows="3" />
            <ValidationMessage For="() => Model.Reason" />
        </div>

        <button type="submit" class="btn btn-primary">Book Appointment</button>
    }
</EditForm>

@if (!showStep2)
{
    <button class="btn btn-secondary mt-3" @onclick="CheckAvailability">Check Availability</button>
}

@if (appointmentConfirmed)
{
    <div class="alert alert-success mt-3">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool appointmentConfirmed;
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();

        // Validate step 1 fields using a temporary EditContext
        editContext = new EditContext(Model);
        var validationMessageStore = new ValidationMessageStore(editContext);

        var isValid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            validationMessageStore.Add(() => Model.PatientName, "Patient Name is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            validationMessageStore.Add(() => Model.Email, "Email is required.");
            isValid = false;
        }
        else if (!IsValidEmail(Model.Email))
        {
            validationMessageStore.Add(() => Model.Email, "Invalid email format.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            validationMessageStore.Add(() => Model.Phone, "Phone is required.");
            isValid = false;
        }

        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            validationMessageStore.Add(() => Model.InsuranceProvider, "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (!isValid)
        {
            return;
        }

        showStep2 = true;
        await LoadTimeSlots();
    }

    private async Task OnDoctorOrDateChanged()
    {
        await LoadTimeSlots();
    }

    private async Task LoadTimeSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate != default)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate);
        }
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        appointmentConfirmed = false;

        // Run server-side validation
        var errors = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            serverErrors = errors;
            return;
        }

        appointmentConfirmed = true;
    }

    private static bool IsValidEmail(string email)
    {
        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email;
        }
        catch
        {
            return false;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_219298d83a2d4e85ac6f11724fbe0645.Models;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient Name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance Provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    [Required(ErrorMessage = "Preferred Doctor is required.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateOnly AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time Slot is required.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string Reason { get; set; } = string.Empty;
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date)
        {
            if (date <= DateOnly.FromDateTime(DateTime.Today))
            {
                return new ValidationResult(ErrorMessage);
            }
        }
        return ValidationResult.Success;
    }
}

